1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	interface Item {
12	  type: string;
13	  cursed?: boolean;
14	}
15	
16	const CURSE_RATE = 0.5;
17	
18	interface QuoteStep {
19	  op: "quote";
20	  items: Item[];
21	}
22	
23	interface Scenario {
24	  customer: { yearsWithMHPCO: number };
25	  steps: QuoteStep[];
26	}
27	
28	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
29	const COMPONENT_BASE = 25;
30	const BLOCK_SIZE = 3;
31	const BLOCK_BASE = 60;
32	
33	const componentBase = (count: number): number =>
34	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
35	
36	const baseForType = (type: string, count: number): number =>
37	  COMPONENT_TYPES.has(type)
38	    ? componentBase(count)
39	    : (BASE_PREMIUMS[type] ?? 0) * count;
40	
41	const countByType = (items: Item[]): Map<string, number> =>
42	  items.reduce(
43	    (counts, item) =>
44	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
45	    new Map<string, number>(),
46	  );
47	
48	const baseForItems = (items: Item[]): number =>
49	  [...countByType(items)].reduce(
50	    (total, [type, count]) => total + baseForType(type, count),
51	    0,
52	  );
53	
54	const itemBase = (item: Item): number =>
55	  COMPONENT_TYPES.has(item.type)
56	    ? COMPONENT_BASE
57	    : (BASE_PREMIUMS[item.type] ?? 0);
58	
59	const itemSurcharges = (item: Item): number =>
60	  (item.cursed ? CURSE_RATE * itemBase(item) : 0);
61	
62	const priceQuote = (items: Item[]): { premium: number } => {
63	  const policyBase = baseForItems(items);
64	  const surcharges = items.reduce((sum, item) => sum + itemSurcharges(item), 0);
65	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
66	  const premium = Math.ceil(
67	    policyBase + surcharges + firstInsuranceSurcharge + PROCESSING_FEE,
68	  );
69	  return { premium };
70	};
71	
72	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
73	  const results = scenario.steps.map((step) => priceQuote(step.items));
74	  return { results };
75	};
